INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf18ee80-5dd1-4c12-9e38-a3430262d485', $q$Inbox Rotation$q$, $q$Automatically distributes outbound email sends across every connected mailbox to protect sender reputation and reduce spam-folder placement.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf18ee80-5dd1-4c12-9e38-a3430262d485', $q$Free Email Warm-Up (MailFlow)$q$, $q$Built-in automated warm-up tool that gradually increases sending volume on new domains and mailboxes to establish deliverability.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf18ee80-5dd1-4c12-9e38-a3430262d485', $q$LinkedIn Outreach$q$, $q$Browser extension for building prospect lists with LinkedIn's ICP filters and running connection and messaging sequences alongside email.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf18ee80-5dd1-4c12-9e38-a3430262d485', $q$Unified Inbox$q$, $q$Consolidates replies from both email and LinkedIn channels into a single inbox for faster follow-up.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf18ee80-5dd1-4c12-9e38-a3430262d485', $q$AI Reword Tool$q$, $q$Uses AI to vary email copy across a campaign, helping reduce detection by spam filters that flag repeated messaging patterns.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf18ee80-5dd1-4c12-9e38-a3430262d485', $q$Deliverability Insights$q$, $q$Automated monitoring that flags sending reputation issues and blacklist placement before they affect campaign performance.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf18ee80-5dd1-4c12-9e38-a3430262d485', $q$CRM Integrations$q$, $q$Native connections to HubSpot and Pipedrive, with Zapier, API and webhook access available on higher-tier plans.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf18ee80-5dd1-4c12-9e38-a3430262d485', $q$No Per-Seat Pricing$q$, $q$Unlimited users and unlimited senders on every plan, with pricing based on monthly email volume instead of team size.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bf18ee80-5dd1-4c12-9e38-a3430262d485', $q$No per-seat pricing; unlimited users and senders included on every plan$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bf18ee80-5dd1-4c12-9e38-a3430262d485', $q$Combines email and LinkedIn outreach in a single campaign workflow$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bf18ee80-5dd1-4c12-9e38-a3430262d485', $q$Built-in warm-up and inbox rotation reduce spam-folder placement without extra tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bf18ee80-5dd1-4c12-9e38-a3430262d485', $q$Responsive customer support frequently praised in user reviews$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bf18ee80-5dd1-4c12-9e38-a3430262d485', $q$No long-term contract required, with a 14-day free trial on every plan$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bf18ee80-5dd1-4c12-9e38-a3430262d485', $q$Starter plan pricing is higher than some budget-focused cold email competitors$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bf18ee80-5dd1-4c12-9e38-a3430262d485', $q$Reporting and analytics are less granular than dedicated enterprise sales engagement platforms$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bf18ee80-5dd1-4c12-9e38-a3430262d485', $q$Multi-step, multi-channel sequence setup has a learning curve for new users$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bf18ee80-5dd1-4c12-9e38-a3430262d485', $q$Email and contact volume caps mean growing teams need to upgrade tiers over time$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bf18ee80-5dd1-4c12-9e38-a3430262d485', $q$API and webhook access are limited to Growth and Agency plans$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bf18ee80-5dd1-4c12-9e38-a3430262d485', $q$What is QuickMail used for?$q$, $q$QuickMail is used for running cold email and LinkedIn outreach campaigns, managing sender deliverability, and consolidating replies from multiple outbound channels into one inbox.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bf18ee80-5dd1-4c12-9e38-a3430262d485', $q$How much does QuickMail cost?$q$, $q$QuickMail starts at $49/month for the Starter plan, with Growth at $99/month and Agency at $299/month, all billed monthly with a 14-day free trial.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bf18ee80-5dd1-4c12-9e38-a3430262d485', $q$Does QuickMail charge per user or per mailbox?$q$, $q$No. QuickMail includes unlimited users, unlimited email senders and unlimited LinkedIn accounts on every plan; pricing is based on monthly email volume and contact limits instead.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bf18ee80-5dd1-4c12-9e38-a3430262d485', $q$Does QuickMail include LinkedIn outreach?$q$, $q$Yes. A browser extension lets users build LinkedIn prospect lists and run connection and messaging sequences alongside email campaigns, with replies unified in one inbox.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bf18ee80-5dd1-4c12-9e38-a3430262d485', $q$Is there a free trial?$q$, $q$QuickMail offers a 14-day free trial on all plans, with no automatic charge after the trial ends and no long-term contract required.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bf18ee80-5dd1-4c12-9e38-a3430262d485', $q$What CRMs does QuickMail integrate with?$q$, $q$QuickMail natively integrates with HubSpot and Pipedrive, and offers Zapier, API and webhook connections on Growth and Agency plans for other tools.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bf18ee80-5dd1-4c12-9e38-a3430262d485', $q$Who founded QuickMail and where is it based?$q$, $q$QuickMail was founded in 2014 by Jeremy Chatelaine and is headquartered in Zurich, Switzerland.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bf18ee80-5dd1-4c12-9e38-a3430262d485', $q$What is Inbox Rotation in QuickMail?$q$, $q$Inbox Rotation automatically spreads campaign sends across all of a user's connected mailboxes, lowering the daily volume per mailbox to help protect sender reputation.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bf18ee80-5dd1-4c12-9e38-a3430262d485', $q$B2B Sales Teams Running Outbound Campaigns$q$, $q$Sales development teams use QuickMail to run coordinated email and LinkedIn sequences, manage multiple sender mailboxes, and track replies in one place without paying per seat.$q$, $q$B2B sales development and business development teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bf18ee80-5dd1-4c12-9e38-a3430262d485', $q$Lead Generation Agencies Managing Client Campaigns$q$, $q$Agencies use QuickMail's multi-workspace support to isolate and manage outreach campaigns for different clients while sharing infrastructure tools like warm-up and deliverability monitoring.$q$, $q$Lead generation and outbound marketing agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bf18ee80-5dd1-4c12-9e38-a3430262d485', $q$Founders and Growth Marketers Doing Outbound Demand Generation$q$, $q$Early-stage founders and growth marketers use QuickMail to run high-volume outbound campaigns for pipeline generation without needing a large sales engagement platform budget.$q$, $q$Startup founders and growth marketing teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bf18ee80-5dd1-4c12-9e38-a3430262d485', $q$Starter$q$, $q$$49/month$q$, $q$Monthly, 14-day free trial$q$, NULL, $q$["Unlimited email senders","Unlimited LinkedIn accounts","Unlimited users","1 workspace","1,000 uploaded contacts","5,000 emails per month","Free AutoWarmer with MailFlow","Zapier integration"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bf18ee80-5dd1-4c12-9e38-a3430262d485', $q$Growth$q$, $q$$99/month$q$, $q$Monthly, 14-day free trial$q$, NULL, $q$["Unlimited email senders","Unlimited LinkedIn accounts","Unlimited users","1 workspace","25,000 uploaded contacts","100,000 emails per month","Zapier and API integrations","Priority expert support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bf18ee80-5dd1-4c12-9e38-a3430262d485', $q$Agency$q$, $q$$299/month$q$, $q$Monthly, 14-day free trial$q$, NULL, $q$["Unlimited email senders","Unlimited LinkedIn accounts","Unlimited users","2 workspaces (additional workspaces $49 each)","100,000 uploaded contacts","500,000 emails per month","Zapier, API and webhook integrations","Priority expert support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bf18ee80-5dd1-4c12-9e38-a3430262d485', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$QuickMail is a cold outreach platform focused on combining email and LinkedIn prospecting into a single, manageable workflow. Rather than charging per user or per mailbox, the company built its pricing around monthly sending volume, which makes it attractive to teams that connect many mailboxes to spread out sending load without paying extra per seat.$q$, $q$Founded in 2014 and based in Zurich, Switzerland, QuickMail has grown into a tool used by sales teams, agencies and solo founders who need reliable deliverability at scale. The platform emphasizes automated infrastructure management, such as email warm-up and inbox rotation, so users spend less time manually protecting sender reputation.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bf18ee80-5dd1-4c12-9e38-a3430262d485', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$QuickMail's Inbox Rotation feature spreads campaign sends across every connected sender, reducing the volume any single mailbox sends per day and lowering the risk of spam-folder placement. This is paired with MailFlow, a free automated warm-up tool included on every plan that gradually builds sending reputation for new domains and mailboxes.$q$, $q$Beyond email, QuickMail connects to LinkedIn through a browser extension, letting users build target lists with LinkedIn's ICP filters and run connection and messaging sequences in parallel with email sequences. Replies from both channels land in one unified inbox, and an AI rewrite tool helps vary messaging copy across large campaigns to avoid pattern-based spam detection.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bf18ee80-5dd1-4c12-9e38-a3430262d485', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$QuickMail offers three paid tiers, all with a 14-day free trial and no contract requirement: Starter at $49/month, Growth at $99/month, and Agency at $299/month. Every tier includes unlimited email senders, unlimited LinkedIn accounts and unlimited users, with the price difference driven by monthly email volume, uploaded contact limits and the number of workspaces included.$q$, $q$Agencies managing multiple client accounts can add extra workspaces to the Agency plan for $49 each, and higher tiers unlock priority support along with deeper integrations such as API and webhook access, which are not available on the Starter plan.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('84a38488-775c-4325-9b1d-4639474c2773', $q$Core File Management$q$, $q$Upload, download, create, delete and move files and folders directly from a browser-based interface.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('84a38488-775c-4325-9b1d-4639474c2773', $q$Resumable Transfers$q$, $q$Uploads and downloads can resume after a network interruption instead of restarting from the beginning.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('84a38488-775c-4325-9b1d-4639474c2773', $q$Anonymous and Link-Based Sharing$q$, $q$Share individual files or entire directories via links, including anonymous access that does not require the recipient to create an account.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('84a38488-775c-4325-9b1d-4639474c2773', $q$QR Code Sharing$q$, $q$Generates QR codes for shared folders so they can be opened instantly on a mobile device.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('84a38488-775c-4325-9b1d-4639474c2773', $q$Multi-User Roles and Quotas$q$, $q$Supports multiple user accounts with user or admin roles, plus per-user storage quotas and upload/download speed limits.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('84a38488-775c-4325-9b1d-4639474c2773', $q$Fuzzy Multi-Keyword Search$q$, $q$Search across files and folders using multiple keywords to quickly locate content in large libraries.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('84a38488-775c-4325-9b1d-4639474c2773', $q$Cross-Platform Deployment$q$, $q$Runs on Linux, macOS and Windows, and can be deployed via a downloaded binary or a Docker container.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('84a38488-775c-4325-9b1d-4639474c2773', $q$Internationalized, Adaptive UI$q$, $q$Interface adapts to different screen sizes and supports multiple display languages through built-in i18n.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('84a38488-775c-4325-9b1d-4639474c2773', $q$Completely free and open source with no subscription cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('84a38488-775c-4325-9b1d-4639474c2773', $q$Full data ownership since files stay on infrastructure the user controls$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('84a38488-775c-4325-9b1d-4639474c2773', $q$Lightweight and simple compared to larger self-hosted platforms$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('84a38488-775c-4325-9b1d-4639474c2773', $q$Resumable uploads and downloads improve reliability on unstable connections$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('84a38488-775c-4325-9b1d-4639474c2773', $q$Docker support makes deployment straightforward for self-hosters$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('84a38488-775c-4325-9b1d-4639474c2773', $q$Active maintenance with regular tagged releases$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('84a38488-775c-4325-9b1d-4639474c2773', $q$Requires technical setup and server maintenance since it is self-hosted$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('84a38488-775c-4325-9b1d-4639474c2773', $q$No official commercial support; help comes from GitHub issues and community channels$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('84a38488-775c-4325-9b1d-4639474c2773', $q$Smaller feature set than full groupware platforms like Nextcloud$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('84a38488-775c-4325-9b1d-4639474c2773', $q$Maintained largely by a single developer, which is a bus-factor risk for long-term support$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('84a38488-775c-4325-9b1d-4639474c2773', $q$No built-in office suite, calendar or collaboration tools beyond file sharing$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('84a38488-775c-4325-9b1d-4639474c2773', $q$What is Quickshare used for?$q$, $q$Quickshare is used for sharing and transferring files between personal devices or with other people, using self-hosted software that the user installs on their own server or computer.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('84a38488-775c-4325-9b1d-4639474c2773', $q$Is Quickshare free?$q$, $q$Yes. Quickshare is free and open-source software released under the LGPL-3.0 license, with no subscription fees or paid tiers.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('84a38488-775c-4325-9b1d-4639474c2773', $q$Do I need to host Quickshare myself?$q$, $q$Yes. Quickshare is self-hosted, meaning it runs on infrastructure the user provides, such as a home server, NAS or cloud VPS, either from a downloaded binary or a Docker container.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('84a38488-775c-4325-9b1d-4639474c2773', $q$What technology is Quickshare built with?$q$, $q$Quickshare is built with Go on the backend and React with TypeScript on the frontend.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('84a38488-775c-4325-9b1d-4639474c2773', $q$Does Quickshare support multiple users?$q$, $q$Yes. Quickshare supports multiple user accounts with role-based permissions (user or admin), along with per-user storage quotas and speed limits.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('84a38488-775c-4325-9b1d-4639474c2773', $q$Can I share files anonymously with Quickshare?$q$, $q$Yes. Quickshare supports anonymous, link-based sharing of files and folders that does not require the recipient to create an account.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('84a38488-775c-4325-9b1d-4639474c2773', $q$What platforms does Quickshare run on?$q$, $q$Quickshare is cross-platform and runs on Linux, macOS and Windows.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('84a38488-775c-4325-9b1d-4639474c2773', $q$Who maintains Quickshare?$q$, $q$Quickshare is maintained on GitHub primarily by developer ihexxa, with contributions from the open-source community; there is no traditional company behind the project.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('84a38488-775c-4325-9b1d-4639474c2773', $q$Personal Cross-Device File Transfer$q$, $q$Individuals use Quickshare to move files quickly between their own phone, laptop and desktop without uploading data to a third-party cloud service.$q$, $q$Individuals and privacy-conscious self-hosters$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('84a38488-775c-4325-9b1d-4639474c2773', $q$Home Server and Small Office File Sharing$q$, $q$Households or small offices deploy Quickshare on a home server or NAS to share files among multiple users with individual storage quotas and permissions.$q$, $q$Home lab enthusiasts and small office IT setups$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('84a38488-775c-4325-9b1d-4639474c2773', $q$Lightweight Alternative to Full Cloud Storage Platforms$q$, $q$Self-hosters who find platforms like Nextcloud too heavy use Quickshare as a simpler, single-purpose file sharing tool that is faster to deploy and maintain.$q$, $q$Self-hosting hobbyists and developers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('84a38488-775c-4325-9b1d-4639474c2773', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$No subscription; one-time download and self-hosted deployment$q$, NULL, $q$["Unlimited use on infrastructure the user controls","File upload, download, creation, deletion and move operations","Resumable uploads and downloads","Multi-user support with role-based permissions","Per-user storage quotas and bandwidth limits","Docker and binary deployment options"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('84a38488-775c-4325-9b1d-4639474c2773', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Quickshare is an open-source file sharing tool designed for people who want to move files between their own devices, or share them with others, without routing everything through a third-party cloud provider. It runs as a self-hosted application, meaning the user installs and operates the software themselves on a server, home computer or small cloud instance they control.$q$, $q$Built with Go, React and TypeScript, the project is maintained on GitHub by developer ihexxa and released under the LGPL-3.0 license. Because it is free and open source, there is no vendor, subscription, or company behind it in the traditional sense; instead, ongoing development happens through community contributions and the maintainer's release cycle, with the latest tagged version being v0.11.4.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('84a38488-775c-4325-9b1d-4639474c2773', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Quickshare covers the core file management operations users expect: uploading, downloading, creating, deleting and moving files and folders, with resumable transfers so large files can recover from interrupted connections rather than restarting from scratch. A fuzzy, multi-keyword search helps users locate files quickly across large folder structures.$q$, $q$Sharing is built around directory-level and file-level links, including anonymous sharing so recipients do not need an account, plus QR code generation for quick mobile access to a shared folder. Multi-user support with role-based permissions, per-user storage quotas and per-user bandwidth limits make the tool practical for households or small teams sharing a single server instance.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('84a38488-775c-4325-9b1d-4639474c2773', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Quickshare has no pricing plans because it is free, open-source software distributed under the LGPL-3.0 license. Users download the source code or a pre-built binary from GitHub, or pull the Docker image, and run it on infrastructure they already own or pay for separately, such as a home server or a cloud VPS.$q$, $q$Because there is no vendor relationship, there are no subscription tiers, feature paywalls, or usage-based charges from the project itself; the only ongoing cost is whatever hosting infrastructure the user chooses to run it on.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('84a38488-775c-4325-9b1d-4639474c2773', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('84a38488-775c-4325-9b1d-4639474c2773', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ad07660-a8fd-4c45-a63d-f9199fe54fa9', $q$Search Directly on Object Storage$q$, $q$Queries data in place on S3, MinIO, Ceph and similar object storage systems without requiring a separate local-disk ingestion step.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ad07660-a8fd-4c45-a63d-f9199fe54fa9', $q$Rust and Tantivy-Based Performance$q$, $q$Built in Rust on the Tantivy search library with vectorized processing and SIMD instructions for high-throughput, sub-second search.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ad07660-a8fd-4c45-a63d-f9199fe54fa9', $q$Decoupled Compute and Storage$q$, $q$Search compute scales independently of data volume, allowing cost-efficient scaling for very large log and trace datasets.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ad07660-a8fd-4c45-a63d-f9199fe54fa9', $q$Native Observability Data Support$q$, $q$Ingests OpenTelemetry and Jaeger tracing formats natively, making it suited for observability and distributed tracing pipelines.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ad07660-a8fd-4c45-a63d-f9199fe54fa9', $q$Schemaless, Multi-Tenant Indexing$q$, $q$Supports schemaless data ingestion and multi-tenant partitioning for teams managing logs across multiple products or customers.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ad07660-a8fd-4c45-a63d-f9199fe54fa9', $q$GDPR-Compliant Deletion$q$, $q$Built-in support for compliant data deletion, relevant for regulated industries with strict data retention rules.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ad07660-a8fd-4c45-a63d-f9199fe54fa9', $q$REST API Access$q$, $q$Exposes a REST API for integration into existing log pipelines, dashboards and observability tooling.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ad07660-a8fd-4c45-a63d-f9199fe54fa9', $q$Flexible Deployment Models$q$, $q$Deployable as a single node or multi-node cluster, on-premise or in the cloud, under the Apache License 2.0.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1ad07660-a8fd-4c45-a63d-f9199fe54fa9', $q$Free and open source under the permissive Apache License 2.0$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1ad07660-a8fd-4c45-a63d-f9199fe54fa9', $q$Searches data directly on low-cost object storage, reducing infrastructure spend versus disk-replicated search engines$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1ad07660-a8fd-4c45-a63d-f9199fe54fa9', $q$High-performance Rust and Tantivy-based architecture built for large-scale log and trace search$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1ad07660-a8fd-4c45-a63d-f9199fe54fa9', $q$Native support for OpenTelemetry and Jaeger, easing adoption in existing observability stacks$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1ad07660-a8fd-4c45-a63d-f9199fe54fa9', $q$Now backed by Datadog's engineering resources following the 2025 acquisition$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1ad07660-a8fd-4c45-a63d-f9199fe54fa9', $q$Future commercial direction is now tied to Datadog's roadmap rather than an independent company$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1ad07660-a8fd-4c45-a63d-f9199fe54fa9', $q$Self-managed deployment requires in-house expertise to operate and tune at scale$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1ad07660-a8fd-4c45-a63d-f9199fe54fa9', $q$Smaller community and ecosystem compared to long-established engines like Elasticsearch$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1ad07660-a8fd-4c45-a63d-f9199fe54fa9', $q$Documentation and tooling maturity may lag more established, decade-old search platforms$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1ad07660-a8fd-4c45-a63d-f9199fe54fa9', $q$Enterprise support now flows through Datadog rather than a dedicated Quickwit team$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1ad07660-a8fd-4c45-a63d-f9199fe54fa9', $q$What is Quickwit used for?$q$, $q$Quickwit is used as a search and analytics engine for logs and distributed traces, allowing teams to run sub-second searches directly on data stored in cloud object storage.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1ad07660-a8fd-4c45-a63d-f9199fe54fa9', $q$Is Quickwit free to use?$q$, $q$Yes. Quickwit is open-source software released under the Apache License 2.0, so it can be self-hosted and used without licensing fees.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1ad07660-a8fd-4c45-a63d-f9199fe54fa9', $q$Who owns Quickwit now?$q$, $q$Quickwit was acquired by Datadog in January 2025. The open-source engine remains available, while enterprise and managed support are now offered through Datadog.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1ad07660-a8fd-4c45-a63d-f9199fe54fa9', $q$What programming language is Quickwit built in?$q$, $q$Quickwit is built in Rust and uses the Tantivy full-text search library as its core indexing engine.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1ad07660-a8fd-4c45-a63d-f9199fe54fa9', $q$Does Quickwit require local disk storage?$q$, $q$No. Quickwit is designed to query data directly on object storage systems like Amazon S3, MinIO and Ceph, avoiding the need to replicate data onto local disks.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1ad07660-a8fd-4c45-a63d-f9199fe54fa9', $q$When was Quickwit founded?$q$, $q$Quickwit was founded in 2020 by a team of engineers with backgrounds in search technology.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1ad07660-a8fd-4c45-a63d-f9199fe54fa9', $q$Does Quickwit support distributed tracing data?$q$, $q$Yes. Quickwit natively supports ingesting OpenTelemetry and Jaeger tracing formats, making it suitable for observability use cases beyond plain log search.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1ad07660-a8fd-4c45-a63d-f9199fe54fa9', $q$How much funding did Quickwit raise before being acquired?$q$, $q$Quickwit raised a $2.6 million seed round in March 2022 led by firstminute Capital and FirstMark before being acquired by Datadog in January 2025.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1ad07660-a8fd-4c45-a63d-f9199fe54fa9', $q$Cost-Efficient Log Search at Scale$q$, $q$Engineering teams use Quickwit to search very large volumes of application and infrastructure logs without paying for expensive, locally-replicated search indexes.$q$, $q$Platform engineering and DevOps teams managing high log volumes$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1ad07660-a8fd-4c45-a63d-f9199fe54fa9', $q$Regulated-Industry Log Residency$q$, $q$Organizations in finance, insurance and healthcare use self-hosted Quickwit to keep log data within specific regions or environments for compliance while still enabling fast search.$q$, $q$Compliance-driven teams in regulated industries$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1ad07660-a8fd-4c45-a63d-f9199fe54fa9', $q$Distributed Tracing and Observability Pipelines$q$, $q$Teams running OpenTelemetry or Jaeger-based tracing use Quickwit to store and search trace data cost-effectively as part of their observability stack.$q$, $q$Site reliability engineers and observability teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1ad07660-a8fd-4c45-a63d-f9199fe54fa9', $q$Open Source (Self-Managed)$q$, $q$Free$q$, $q$No subscription; self-hosted under Apache License 2.0$q$, NULL, $q$["Full search and indexing engine source code","Deployable on any supported object storage (S3, MinIO, Ceph)","Community support via GitHub and Discord","Single-node or multi-node deployment"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1ad07660-a8fd-4c45-a63d-f9199fe54fa9', $q$Datadog-Managed Offering$q$, $q$Custom pricing (via Datadog)$q$, $q$Enterprise agreement through Datadog$q$, NULL, $q$["Managed deployment and support","Integration with Datadog's observability suite","Enterprise SLAs"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1ad07660-a8fd-4c45-a63d-f9199fe54fa9', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Quickwit is a search engine designed specifically for the scale and cost challenges of modern log management, letting teams run sub-second searches directly against data stored in cheap object storage like Amazon S3, rather than requiring that data to be duplicated into expensive, locally-attached search indexes.$q$, $q$Founded in 2020 and built by a team with deep search-technology expertise, Quickwit was acquired by Datadog in January 2025 to strengthen Datadog's log management and observability capabilities, particularly for regulated industries with strict data residency requirements. As part of the deal, Quickwit committed to releasing a major update under the Apache License 2.0 to keep the technology open for its existing community.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1ad07660-a8fd-4c45-a63d-f9199fe54fa9', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Quickwit is written in Rust and built on the Tantivy search library, using vectorized processing and SIMD instructions for high query throughput. Its architecture separates compute from storage, so search capacity can scale independently of data volume, and it queries object storage directly rather than requiring a separate, costly ingestion pipeline into local disk-based indexes.$q$, $q$The engine is schemaless, horizontally scalable, and supports multi-tenant partitioning, with native ingestion support for OpenTelemetry and Jaeger tracing formats, GDPR-compliant deletion, and a REST API for integration into existing observability pipelines. It can be deployed as a single node or as a multi-node cluster, on-premise or in the cloud.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1ad07660-a8fd-4c45-a63d-f9199fe54fa9', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Quickwit itself is free and open source, distributed under the Apache License 2.0, so any organization can download and self-host it without licensing fees. Prior to its acquisition, Quickwit also offered commercial support and a managed cloud option directly.$q$, $q$Following the January 2025 acquisition by Datadog, enterprise and managed support for Quickwit's underlying technology is now accessed through Datadog's commercial products and pricing, while the open-source engine remains separately available for self-managed deployments.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1ad07660-a8fd-4c45-a63d-f9199fe54fa9', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$AI Paraphrasing with Multiple Modes$q$, $q$Rewrites text in Standard, Fluency, Formal, Academic, Simple, Creative, Expand and Shorten modes to match different tones and audiences.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Grammar and Punctuation Checker$q$, $q$Flags grammar, punctuation and word-choice issues and suggests corrections alongside the paraphrasing tool.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Plagiarism Checker$q$, $q$Scans submitted text against billions of web pages and academic sources to detect potential plagiarism, available on Premium.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$AI Summarizer$q$, $q$Condenses long documents or articles into shorter summaries while preserving key points.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Citation Generator$q$, $q$Automatically generates citations in APA, MLA, Chicago and other common academic styles.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$QuillBot Translate$q$, $q$AI-powered translation tool supporting more than 50 languages for cross-language writing and communication.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Browser and Document Integrations$q$, $q$Available as a Chrome extension and Microsoft Word add-in, plus iOS and Android apps, for in-context writing assistance.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Team and Student Plans$q$, $q$Offers discounted Team pricing for small groups and reduced-rate Premium access for verified students.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Free plan available for casual, low-volume paraphrasing needs$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Multiple paraphrasing modes allow fine control over tone and style$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Bundles grammar checking, plagiarism detection, summarizing, citations and translation in one subscription$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Annual billing offers a substantial discount versus monthly pricing$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Browser extension and Word integration make it easy to use inside existing writing workflows$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Discounted student and small-team pricing options$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Free plan's 125-word paraphrasing limit is restrictive for longer documents$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Heavily paraphrased academic text can occasionally read as awkward or unnatural$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Increasing competition from general-purpose AI chat tools that offer similar rewriting capabilities$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Premium pricing adds up for users who only need occasional paraphrasing$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Some advanced features like plagiarism checking are locked behind the paid tier$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Translation quality can vary for less common language pairs compared to dedicated translation services$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$What is QuillBot used for?$q$, $q$QuillBot is used for paraphrasing and rewriting text, checking grammar and punctuation, detecting plagiarism, summarizing documents, generating citations and translating text between languages.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$How much does QuillBot Premium cost?$q$, $q$QuillBot Premium costs $19.95/month billed monthly, $39.95 per quarter (about $13.31/month), or $99.95 per year (about $8.33/month).$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Is QuillBot free to use?$q$, $q$Yes, QuillBot offers a free plan with a 125-word paraphrasing limit and basic grammar checking; Premium removes the word limit and unlocks additional tools.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Who owns QuillBot?$q$, $q$QuillBot was founded in 2017 and acquired in 2021 by Learneo, Inc. (formerly Course Hero), which continues to operate it as one of its core products.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Does QuillBot offer a plagiarism checker?$q$, $q$Yes, QuillBot includes a plagiarism checker that scans text against billions of web and academic sources, available on the Premium plan.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$How many languages does QuillBot support for translation?$q$, $q$QuillBot Translate supports more than 50 languages for AI-powered translation.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Does QuillBot have a browser extension?$q$, $q$Yes, QuillBot offers a Chrome browser extension along with a Microsoft Word add-in and mobile apps for iOS and Android.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Is there a discount for students or teams?$q$, $q$Yes, QuillBot offers discounted Premium access for verified students and a Team plan starting around $7.50 per user per month for 2 to 10 seats billed annually.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Academic Writing and Research$q$, $q$Students and researchers use QuillBot to paraphrase source material, check grammar, detect unintentional plagiarism and generate citations for papers and assignments.$q$, $q$Students, graduate researchers and academics$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Content Writing and Marketing$q$, $q$Content writers and marketers use QuillBot to quickly rework drafts, vary phrasing across articles, and polish grammar before publishing.$q$, $q$Content writers, copywriters and marketing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Non-Native English Writing Support$q$, $q$Non-native English speakers use QuillBot's paraphrasing, grammar checking and translation tools to write more fluently and confidently in English.$q$, $q$Non-native English speakers and international professionals$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Free$q$, $q$$0$q$, $q$Free forever$q$, NULL, $q$["125-word paraphrasing limit per rewrite","Basic paraphrasing modes","Basic grammar checking"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Premium (Monthly)$q$, $q$$19.95/month$q$, $q$Monthly$q$, NULL, $q$["Unlimited-length paraphrasing","Advanced grammar and word-choice suggestions","Plagiarism checker","Translation tools","Priority support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Premium (Quarterly)$q$, $q$$39.95 per quarter (about $13.31/month)$q$, $q$Quarterly$q$, NULL, $q$["All Premium features"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Premium (Annual)$q$, $q$$99.95/year (about $8.33/month)$q$, $q$Annual$q$, NULL, $q$["All Premium features","Largest discount versus monthly billing"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$Team$q$, $q$From $7.50/user/month$q$, $q$Annual, 2 to 10 seats$q$, NULL, $q$["All Premium features per seat","Centralized billing","Team management tools"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$QuillBot is an AI writing assistant centered on paraphrasing, helping users rewrite sentences and paragraphs in different tones while keeping the original meaning intact. Formed in 2017 and based in Chicago, Illinois, QuillBot was acquired in 2021 by Learneo (formerly Course Hero), and continues to operate under its own brand as one of Learneo's core products.$q$, $q$Beyond paraphrasing, QuillBot has expanded into a full writing suite that includes grammar checking, plagiarism detection, text summarization, citation generation and multi-language translation, positioning it as a one-stop tool for students, non-native English speakers, and professional writers who need to refine and polish text quickly.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$QuillBot's paraphrasing tool offers multiple modes, including Standard, Fluency, Formal, Academic, Simple, Creative, Expand and Shorten, so users can adapt output for casual writing, academic papers, or professional communication. The grammar checker flags punctuation, word choice and sentence structure issues alongside the paraphraser.$q$, $q$Additional tools include a plagiarism checker that scans against billions of web and academic sources, an AI summarizer for condensing long documents, a citation generator supporting APA, MLA and Chicago styles, and QuillBot Translate, which supports more than 50 languages. A Chrome extension, Word add-in, and mobile apps bring these tools into the environments users already write in.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f18cd757-37d4-43bb-966d-11c389f63bb7', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$QuillBot uses a freemium model: the Free plan limits paraphrasing to 125 words at a time and includes basic grammar checking, while Premium removes the word limit and adds advanced grammar suggestions, the plagiarism checker, translation tools and priority support.$q$, $q$Premium costs $19.95/month billed monthly, $39.95 per quarter (about $13.31/month), or $99.95 per year (about $8.33/month), the best value at roughly 58 percent savings versus monthly billing. A Team plan for 2 to 10 seats starts around $7.50 per user per month billed annually, and verified students receive discounted Premium access.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0d09ae62-a1c6-4ce0-8abc-c1f4abd82023', $q$Automated Commission Calculation$q$, $q$Connects to CRM, spreadsheet, HRIS, accounting and ERP systems to automatically calculate commissions based on closed deals and plan rules.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0d09ae62-a1c6-4ce0-8abc-c1f4abd82023', $q$AI-Powered Plan Builder$q$, $q$Generates a compensation plan structure from an uploaded strategy document or a text prompt, translating strategy into a configured plan.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0d09ae62-a1c6-4ce0-8abc-c1f4abd82023', $q$Compensation Benchmarking$q$, $q$Compares a company's commission plans against a database of tens of thousands of other plans to guide competitive plan design.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0d09ae62-a1c6-4ce0-8abc-c1f4abd82023', $q$Multi-Level Approval Workflows$q$, $q$Routes commission calculations through configurable approval chains involving reps, managers, executives and finance.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0d09ae62-a1c6-4ce0-8abc-c1f4abd82023', $q$Automated Payroll Sync$q$, $q$Syncs approved commission payouts directly to payroll systems, including a native integration with Rippling.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0d09ae62-a1c6-4ce0-8abc-c1f4abd82023', $q$Ledger and ASC 606 Support$q$, $q$Maintains an auditable ledger of commission data that supports ASC 606 revenue recognition compliance.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0d09ae62-a1c6-4ce0-8abc-c1f4abd82023', $q$What-If Calculators and Rep Dashboards$q$, $q$Gives sales reps visibility into projected earnings under different deal and quota attainment scenarios.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0d09ae62-a1c6-4ce0-8abc-c1f4abd82023', $q$API and SSO Access$q$, $q$Premium and above include API access and single sign-on for deeper integration into enterprise IT environments.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0d09ae62-a1c6-4ce0-8abc-c1f4abd82023', $q$Automates commission calculations that are traditionally handled in error-prone spreadsheets$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0d09ae62-a1c6-4ce0-8abc-c1f4abd82023', $q$AI-Powered Plan Builder speeds up designing new compensation plans$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0d09ae62-a1c6-4ce0-8abc-c1f4abd82023', $q$Deep integration library spanning CRMs, HRIS, accounting and ERP tools on higher tiers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0d09ae62-a1c6-4ce0-8abc-c1f4abd82023', $q$Multi-level approval workflows support compliance and audit requirements$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0d09ae62-a1c6-4ce0-8abc-c1f4abd82023', $q$Benchmarking data helps companies evaluate whether their comp plans are competitive$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0d09ae62-a1c6-4ce0-8abc-c1f4abd82023', $q$Backed by significant funding, suggesting continued product investment$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0d09ae62-a1c6-4ce0-8abc-c1f4abd82023', $q$Pricing combines a per-user rate with a separate platform fee, which can be harder to estimate than flat per-seat pricing$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0d09ae62-a1c6-4ce0-8abc-c1f4abd82023', $q$Advanced features like custom reporting and API access are reserved for the Premium tier and above$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0d09ae62-a1c6-4ce0-8abc-c1f4abd82023', $q$Implementation timelines of 45 to 90 days mean it is not an instant setup$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0d09ae62-a1c6-4ce0-8abc-c1f4abd82023', $q$Strategic tier pricing is custom and not published, requiring a sales conversation$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0d09ae62-a1c6-4ce0-8abc-c1f4abd82023', $q$Smaller integration library on the entry-level Growth plan compared to Premium$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0d09ae62-a1c6-4ce0-8abc-c1f4abd82023', $q$Best suited to teams with structured commission plans rather than very simple flat-rate payouts$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0d09ae62-a1c6-4ce0-8abc-c1f4abd82023', $q$What is QuotaPath used for?$q$, $q$QuotaPath is used to design, automate and track sales commission plans, connecting to CRM, accounting and payroll systems to calculate and pay out commissions accurately.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0d09ae62-a1c6-4ce0-8abc-c1f4abd82023', $q$How much does QuotaPath cost?$q$, $q$QuotaPath's Growth plan costs $35 per user per month plus a $525 monthly platform fee (billed annually), while Premium costs $50 per user per month plus an $800 monthly platform fee.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0d09ae62-a1c6-4ce0-8abc-c1f4abd82023', $q$Does QuotaPath integrate with Salesforce and HubSpot?$q$, $q$Yes. QuotaPath natively integrates with Salesforce, HubSpot and other CRMs, with the number of supported CRMs and other integrations increasing on higher-tier plans.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0d09ae62-a1c6-4ce0-8abc-c1f4abd82023', $q$What is QuotaPath's AI-Powered Plan Builder?$q$, $q$It is a feature that generates a compensation plan structure automatically from an uploaded strategy document or a written prompt, speeding up plan design.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0d09ae62-a1c6-4ce0-8abc-c1f4abd82023', $q$When was QuotaPath founded and where is it based?$q$, $q$QuotaPath was founded in 2018 and is co-headquartered in Philadelphia, Pennsylvania and Austin, Texas.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0d09ae62-a1c6-4ce0-8abc-c1f4abd82023', $q$Does QuotaPath support payroll integration?$q$, $q$Yes, on the Premium plan and above, QuotaPath supports automated commission-to-payroll syncing, including a native integration with Rippling.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0d09ae62-a1c6-4ce0-8abc-c1f4abd82023', $q$What is the Strategic plan?$q$, $q$Strategic is QuotaPath's fully managed, custom-priced tier that includes a dedicated compensation analyst, end-to-end plan design and monthly commission runs handled by QuotaPath's team.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0d09ae62-a1c6-4ce0-8abc-c1f4abd82023', $q$How much funding has QuotaPath raised?$q$, $q$QuotaPath has raised approximately $70.8 million across five funding rounds, including a $21.3 million Series A led by Insight Partners.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0d09ae62-a1c6-4ce0-8abc-c1f4abd82023', $q$RevOps-Led Commission Automation$q$, $q$RevOps teams use QuotaPath to replace manual spreadsheet-based commission tracking with an automated system connected directly to their CRM and payroll tools.$q$, $q$Revenue operations teams at B2B SaaS companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0d09ae62-a1c6-4ce0-8abc-c1f4abd82023', $q$Finance-Driven Compensation Auditing$q$, $q$Finance teams use QuotaPath's ledger and ASC 606 support to maintain auditable records of commission calculations for compliance and revenue recognition purposes.$q$, $q$Finance and accounting teams managing sales compensation$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0d09ae62-a1c6-4ce0-8abc-c1f4abd82023', $q$Sales Leadership Plan Design and Benchmarking$q$, $q$Sales leaders use the AI-Powered Plan Builder and benchmarking data to design new compensation plans and evaluate them against industry data before rolling them out.$q$, $q$Sales leadership and compensation planning teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0d09ae62-a1c6-4ce0-8abc-c1f4abd82023', $q$Growth$q$, $q$$35/user/month plus $525/month platform fee (covers first 5 users)$q$, $q$Annual$q$, NULL, $q$["Quota management","Leaderboards and contests","Manager plans and plan verification","Calculated fields","Ledger and ASC 606 support","6 CRM and 3 spreadsheet integrations"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0d09ae62-a1c6-4ce0-8abc-c1f4abd82023', $q$Premium$q$, $q$$50/user/month plus $800/month platform fee (covers first 5 users)$q$, $q$Annual$q$, NULL, $q$["Everything in Growth","Plan modeling","Multi-level approvals","Custom reporting","Automated commission payroll sync","API access and SSO"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0d09ae62-a1c6-4ce0-8abc-c1f4abd82023', $q$Strategic$q$, $q$Custom pricing$q$, $q$Annual, custom-scoped$q$, NULL, $q$["Dedicated compensation analyst","End-to-end plan design","Monthly commission runs","Dispute resolution support","Scenario modeling and benchmark recommendations"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0d09ae62-a1c6-4ce0-8abc-c1f4abd82023', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$QuotaPath is a compensation management platform built to automate the design, tracking and payout of sales commissions, replacing manual spreadsheet processes that are prone to errors and disputes between sales reps, managers and finance teams.$q$, $q$Founded in 2018 and co-headquartered in Philadelphia and Austin, QuotaPath has raised roughly $70.8 million in funding, including a $21.3 million Series A led by Insight Partners, and counts HubSpot Ventures among its investors, reflecting its close integration with common CRM platforms used by sales teams.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0d09ae62-a1c6-4ce0-8abc-c1f4abd82023', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$QuotaPath connects directly to CRM systems like Salesforce and HubSpot, along with spreadsheets, HRIS, accounting and ERP tools, to automatically calculate commissions based on closed deals and configurable plan rules. Its AI-Powered Plan Builder can generate a compensation plan structure directly from an uploaded document or a written prompt, and AI benchmarking compares a company's plans against tens of thousands of others in its database.$q$, $q$On the higher tiers, QuotaPath adds multi-level approval workflows, custom reporting, automated payroll syncing through partners like Rippling, API access and single sign-on, giving finance and RevOps teams a fully auditable commission process that supports ASC 606 revenue recognition requirements.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0d09ae62-a1c6-4ce0-8abc-c1f4abd82023', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$QuotaPath's pricing combines a per-user rate with a flat monthly platform fee, all billed annually. Growth costs $35 per user per month plus a $525 monthly platform fee covering the first five users, while Premium costs $50 per user per month plus an $800 monthly platform fee, also covering five users.$q$, $q$A third tier, Strategic, offers custom pricing for organizations that want a fully managed commissions service, including a dedicated compensation analyst and monthly commission runs handled by QuotaPath's team rather than configured entirely in-house.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79b50fbc-218a-44ae-a060-2d87cb1dda56', $q$AI Clips Generator$q$, $q$Analyzes long-form video and audio to automatically identify and score the most engaging moments for short-form clips.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79b50fbc-218a-44ae-a060-2d87cb1dda56', $q$Automated Animated Captions$q$, $q$Adds word-level animated subtitles in more than 100 languages, with automatic filler-word and silence removal.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79b50fbc-218a-44ae-a060-2d87cb1dda56', $q$Multi-Format Repurposing$q$, $q$Reformats a single source video into multiple aspect ratios (16:9, 9:16, 1:1) for different social platforms in one pass.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79b50fbc-218a-44ae-a060-2d87cb1dda56', $q$Social Media Scheduler and Content Planner$q$, $q$Plans and auto-publishes clips to multiple platforms from a single calendar-based scheduling view.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79b50fbc-218a-44ae-a060-2d87cb1dda56', $q$Text-Based AI Video Editor$q$, $q$Lets users edit video by editing the transcript, with an included B-roll library for supplementing footage.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79b50fbc-218a-44ae-a060-2d87cb1dda56', $q$Brand Kit$q$, $q$Maintains consistent fonts, colors and logos automatically across all clips generated from a brand's content.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79b50fbc-218a-44ae-a060-2d87cb1dda56', $q$Viddy AI Assistant$q$, $q$An AI assistant available on the top-tier plan to help guide content creation and repurposing decisions.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79b50fbc-218a-44ae-a060-2d87cb1dda56', $q$Social Media Analytics$q$, $q$Provides AI-generated performance insights on published clips to help creators identify what content resonates.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('79b50fbc-218a-44ae-a060-2d87cb1dda56', $q$Free plan available with no credit card required to start$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('79b50fbc-218a-44ae-a060-2d87cb1dda56', $q$Automates the time-consuming process of finding clip-worthy moments in long recordings$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('79b50fbc-218a-44ae-a060-2d87cb1dda56', $q$Captions and transcription support more than 100 languages$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('79b50fbc-218a-44ae-a060-2d87cb1dda56', $q$Publishes to multiple platforms from one scheduling calendar$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('79b50fbc-218a-44ae-a060-2d87cb1dda56', $q$Consolidates functionality otherwise spread across several separate tools$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('79b50fbc-218a-44ae-a060-2d87cb1dda56', $q$Large, established user base of more than four million creators$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('79b50fbc-218a-44ae-a060-2d87cb1dda56', $q$Free plan output is capped at 720p and includes a watermark$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('79b50fbc-218a-44ae-a060-2d87cb1dda56', $q$Credit-based system means heavy users can exhaust monthly credits quickly on lower tiers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('79b50fbc-218a-44ae-a060-2d87cb1dda56', $q$Advanced features like the Viddy AI assistant and unlimited scheduling are reserved for the top-tier Growth plan$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('79b50fbc-218a-44ae-a060-2d87cb1dda56', $q$Storage limits scale with plan tier, which can be restrictive for high-volume creators$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('79b50fbc-218a-44ae-a060-2d87cb1dda56', $q$AI-selected "best moments" still typically require some manual review and adjustment$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('79b50fbc-218a-44ae-a060-2d87cb1dda56', $q$What is Quso.ai used for?$q$, $q$Quso.ai is used to automatically convert long-form videos, podcasts and livestreams into short, captioned clips optimized for platforms like TikTok, Instagram Reels, YouTube Shorts and LinkedIn.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('79b50fbc-218a-44ae-a060-2d87cb1dda56', $q$Was Quso.ai previously called something else?$q$, $q$Yes, Quso.ai was previously branded as Vidyo.ai before rebranding.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('79b50fbc-218a-44ae-a060-2d87cb1dda56', $q$How much does Quso.ai cost?$q$, $q$Quso.ai offers a free plan with 75 monthly credits, with paid plans starting at $19/month billed annually for the Lite plan, up to $33/month annually for the Growth plan.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('79b50fbc-218a-44ae-a060-2d87cb1dda56', $q$How does Quso.ai's credit system work?$q$, $q$Each credit represents roughly one minute of processed video; monthly credit allowances vary by plan and double when billed annually.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('79b50fbc-218a-44ae-a060-2d87cb1dda56', $q$Does Quso.ai support multiple languages for captions?$q$, $q$Yes, Quso.ai generates captions and transcriptions in more than 100 languages.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('79b50fbc-218a-44ae-a060-2d87cb1dda56', $q$Who founded Quso.ai and when?$q$, $q$Quso.ai was co-founded by Vedant Maheshwari and Kushagra Pandya in December 2021 and is headquartered in New York City.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('79b50fbc-218a-44ae-a060-2d87cb1dda56', $q$Can Quso.ai schedule and publish clips automatically?$q$, $q$Yes, the Essential and Growth plans include a Content Planner and scheduler that can auto-publish clips to multiple social platforms.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('79b50fbc-218a-44ae-a060-2d87cb1dda56', $q$What platforms can Quso.ai publish clips to?$q$, $q$Quso.ai supports publishing to platforms including TikTok, Instagram, YouTube Shorts and LinkedIn, with paid plans supporting publishing to six platforms.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('79b50fbc-218a-44ae-a060-2d87cb1dda56', $q$Podcast and Long-Form Video Repurposing$q$, $q$Podcasters and video creators upload full-length episodes and use Quso.ai to automatically generate a batch of short clips for social distribution.$q$, $q$Podcasters and long-form video creators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('79b50fbc-218a-44ae-a060-2d87cb1dda56', $q$Coach and Creator Content Marketing$q$, $q$Business and mindset coaches use Quso.ai to turn webinars and coaching sessions into short-form marketing clips without hiring a dedicated video editor.$q$, $q$Coaches, consultants and personal brand creators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('79b50fbc-218a-44ae-a060-2d87cb1dda56', $q$Agency Multi-Client Content Production$q$, $q$Content and social media agencies use Quso.ai's Brand Kit and scheduling tools to produce and publish branded short-form clips across multiple client accounts.$q$, $q$Content and social media marketing agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('79b50fbc-218a-44ae-a060-2d87cb1dda56', $q$Free$q$, $q$$0/month$q$, $q$Free forever$q$, NULL, $q$["75 clipping credits per month","720p exports","Watermarked clips","TikTok publishing"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('79b50fbc-218a-44ae-a060-2d87cb1dda56', $q$Lite$q$, $q$$19/month billed annually ($29/month billed monthly)$q$, $q$Annual or monthly$q$, NULL, $q$["Unlimited 1080p clips","Advanced desktop editor","Publishing to 6 platforms","10GB storage"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('79b50fbc-218a-44ae-a060-2d87cb1dda56', $q$Essential$q$, $q$$26/month billed annually ($39/month billed monthly)$q$, $q$Annual or monthly$q$, NULL, $q$["Everything in Lite","AI filler and silence removal","Content Planner","25GB storage"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('79b50fbc-218a-44ae-a060-2d87cb1dda56', $q$Growth$q$, $q$$33/month billed annually ($49/month billed monthly)$q$, $q$Annual or monthly$q$, NULL, $q$["Everything in Essential","Custom Brand Kit","Viddy AI assistant","Unlimited scheduling and analytics","75GB storage"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('79b50fbc-218a-44ae-a060-2d87cb1dda56', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Quso.ai, previously branded as Vidyo.ai, is an AI content repurposing platform that turns long-form video and audio, such as podcasts, webinars and livestreams, into short, captioned clips ready for social platforms. Co-founded in December 2021 by Vedant Maheshwari and Kushagra Pandya and based in New York City, the company reports serving more than four million creators worldwide.$q$, $q$The platform's central promise is turning one long recording into a full batch of platform-specific short clips automatically, using AI to find the most engaging moments, add animated captions, and reformat video for different aspect ratios, reducing the manual editing time typically required to repurpose long content into short-form clips.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('79b50fbc-218a-44ae-a060-2d87cb1dda56', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Quso.ai's AI Clips Generator scans uploaded long-form content, identifies high-potential moments and scores them by estimated virality, then produces short clips with word-level animated captions in more than 100 languages and automatic filler-word and silence removal.$q$, $q$The platform also includes a text-based AI video editor with a B-roll library, a Brand Kit for consistent visual branding across clips, and a social media scheduler with a Content Planner that lets users plan and auto-publish clips to multiple platforms, along with AI-powered analytics that surface which clips are performing best.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('79b50fbc-218a-44ae-a060-2d87cb1dda56', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Quso.ai uses a freemium, credit-based pricing model where each credit represents roughly one minute of processed video. The Free plan includes 75 monthly credits with 720p, watermarked exports and TikTok publishing only.$q$, $q$Paid plans start at Lite for $19/month billed annually (or $29/month monthly) for unlimited 1080p exports and multi-platform publishing, scaling up through Essential at $26/month annually and Growth at $33/month annually, which adds a custom Brand Kit, the Viddy AI assistant, unlimited scheduling and priority support. Annual billing is roughly 33 percent cheaper than monthly and doubles included credits.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('06d2781b-fc8f-45ff-905b-0da1b9931d4e', $q$Resumability$q$, $q$Serializes application state into server-rendered HTML and resumes execution in the browser without a traditional hydration step.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('06d2781b-fc8f-45ff-905b-0da1b9931d4e', $q$Fine-Grained Lazy Loading$q$, $q$Loads only the JavaScript needed for a specific user interaction, at the moment that interaction occurs, rather than the entire app bundle upfront.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('06d2781b-fc8f-45ff-905b-0da1b9931d4e', $q$Qwik Optimizer$q$, $q$Automatically splits application code into small, lazily-loadable chunks at build time, using real-user data to prioritize likely-needed code.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('06d2781b-fc8f-45ff-905b-0da1b9931d4e', $q$Qwik City Meta-Framework$q$, $q$Companion framework adding file-based routing, layouts and server-side rendering conventions on top of core Qwik.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('06d2781b-fc8f-45ff-905b-0da1b9931d4e', $q$JSX and React-Familiar Component Model$q$, $q$Uses JSX syntax and component patterns recognizable to React developers, easing migration for existing teams.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('06d2781b-fc8f-45ff-905b-0da1b9931d4e', $q$Vite-Based Tooling$q$, $q$Built on Vite for development and builds, with Vitest and Playwright integrated for unit and end-to-end testing.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('06d2781b-fc8f-45ff-905b-0da1b9931d4e', $q$Multi-Platform Deployment Adapters$q$, $q$Ships with deployment adapters for Vercel, Netlify, Cloudflare Pages, Deno Deploy and Express-based Node servers.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('06d2781b-fc8f-45ff-905b-0da1b9931d4e', $q$MIT-Licensed Open Source$q$, $q$Fully free and open source, with no paid tiers or licensing fees for commercial or personal use.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('06d2781b-fc8f-45ff-905b-0da1b9931d4e', $q$Completely free and open source under the permissive MIT License$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('06d2781b-fc8f-45ff-905b-0da1b9931d4e', $q$Resumability can dramatically improve time-to-interactive on large, content-heavy sites$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('06d2781b-fc8f-45ff-905b-0da1b9931d4e', $q$Familiar JSX and component syntax lowers the learning curve for React developers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('06d2781b-fc8f-45ff-905b-0da1b9931d4e', $q$Backed and actively funded by Builder.io, providing continued development investment$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('06d2781b-fc8f-45ff-905b-0da1b9931d4e', $q$Strong performance benefits for SEO-sensitive, content-heavy sites like marketing pages and storefronts$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('06d2781b-fc8f-45ff-905b-0da1b9931d4e', $q$Broad deployment adapter support across major hosting platforms$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('06d2781b-fc8f-45ff-905b-0da1b9931d4e', $q$Smaller ecosystem and community than long-established frameworks like React, Vue or Angular$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('06d2781b-fc8f-45ff-905b-0da1b9931d4e', $q$Resumability is a fundamentally different mental model that requires a learning curve even for experienced developers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('06d2781b-fc8f-45ff-905b-0da1b9931d4e', $q$Fewer third-party libraries and community components compared to the React ecosystem$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('06d2781b-fc8f-45ff-905b-0da1b9931d4e', $q$Documentation and tooling can lag behind faster-moving mainstream frameworks$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('06d2781b-fc8f-45ff-905b-0da1b9931d4e', $q$Hiring developers with existing Qwik experience is harder given its smaller adoption base$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('06d2781b-fc8f-45ff-905b-0da1b9931d4e', $q$No official managed hosting or paid enterprise support tier from the Qwik project itself$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('06d2781b-fc8f-45ff-905b-0da1b9931d4e', $q$What is Qwik used for?$q$, $q$Qwik is used to build web applications and websites that need to become interactive almost instantly, particularly content-heavy sites where fast time-to-interactive affects SEO and conversion.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('06d2781b-fc8f-45ff-905b-0da1b9931d4e', $q$Is Qwik free to use?$q$, $q$Yes, Qwik is completely free and open source, released under the MIT License, with no paid tiers or licensing fees.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('06d2781b-fc8f-45ff-905b-0da1b9931d4e', $q$Who created Qwik?$q$, $q$Qwik was created by Miško Hevery, the original creator of AngularJS and Angular, along with Adam Bradley and Manu Almeida, and was introduced publicly around 2021.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('06d2781b-fc8f-45ff-905b-0da1b9931d4e', $q$What company backs Qwik's development?$q$, $q$Qwik is primarily developed and sponsored by Builder.io, a San Francisco-based visual headless CMS company founded in 2018, where Hevery serves as CTO.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('06d2781b-fc8f-45ff-905b-0da1b9931d4e', $q$What is resumability in Qwik?$q$, $q$Resumability is Qwik's core technique of serializing application state into server-rendered HTML and resuming execution in the browser without a traditional hydration step, loading JavaScript only when needed.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('06d2781b-fc8f-45ff-905b-0da1b9931d4e', $q$Is Qwik similar to React?$q$, $q$Qwik uses JSX syntax and a component model similar to React, which makes it easier for React developers to learn, though its underlying execution model (resumability) is fundamentally different.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('06d2781b-fc8f-45ff-905b-0da1b9931d4e', $q$What is Qwik City?$q$, $q$Qwik City is Qwik's companion meta-framework that adds file-based routing, layouts and server-side rendering conventions, similar to how Next.js extends React.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('06d2781b-fc8f-45ff-905b-0da1b9931d4e', $q$What platforms can Qwik apps be deployed to?$q$, $q$Qwik includes deployment adapters for Vercel, Netlify, Cloudflare Pages, Deno Deploy and Express-based Node servers, among others.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('06d2781b-fc8f-45ff-905b-0da1b9931d4e', $q$Content-Heavy Marketing Websites$q$, $q$Teams building marketing sites and landing pages use Qwik to achieve fast time-to-interactive, improving both user experience and SEO performance.$q$, $q$Web development teams building marketing and content sites$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('06d2781b-fc8f-45ff-905b-0da1b9931d4e', $q$E-Commerce Storefronts$q$, $q$E-commerce teams use Qwik to reduce interaction delay on product and checkout pages, where faster interactivity can directly impact conversion rates.$q$, $q$E-commerce development teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('06d2781b-fc8f-45ff-905b-0da1b9931d4e', $q$Publishing and Media Platforms$q$, $q$Publishers use Qwik to serve content-heavy pages that load and become interactive quickly even on slower devices and networks.$q$, $q$Digital publishers and media companies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('06d2781b-fc8f-45ff-905b-0da1b9931d4e', $q$Open Source$q$, $q$Free$q$, $q$No subscription; MIT licensed$q$, NULL, $q$["Full framework source code","Qwik City meta-framework for routing and SSR","Community support via Discord and GitHub","Deployment adapters for Vercel, Netlify, Cloudflare, Deno and Express"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('06d2781b-fc8f-45ff-905b-0da1b9931d4e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Qwik is an open-source JavaScript framework built around a technique called resumability, which lets web applications become interactive almost instantly by avoiding the traditional hydration step that most frameworks require before a page responds to user input. It was created by Miško Hevery, the original creator of AngularJS and Angular, along with Adam Bradley and Manu Almeida, and introduced publicly around 2021.$q$, $q$Qwik is developed and sponsored primarily by Builder.io, a San Francisco-based visual headless CMS company founded in 2018 where Hevery serves as CTO. The framework itself remains free, open source and community-maintained under the MIT License, with Builder.io funding core development and the project maintained on GitHub under the QwikDev organization.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('06d2781b-fc8f-45ff-905b-0da1b9931d4e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Qwik's defining feature is resumability: instead of re-executing application logic in the browser to attach event handlers after server rendering, Qwik serializes state into the HTML itself and resumes exactly where the server left off, loading only the JavaScript needed for a specific interaction at the moment it happens.$q$, $q$The framework uses familiar JSX syntax and a component model similar to React, and pairs with Qwik City, a companion meta-framework that adds file-based routing, layouts and server-side rendering conventions. Its tooling includes Vite for development, Vitest and Playwright for testing, and deployment adapters for Vercel, Netlify, Cloudflare, Deno and Express.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('06d2781b-fc8f-45ff-905b-0da1b9931d4e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Qwik has no pricing because it is a free, open-source framework released under the MIT License. There are no paid tiers, subscriptions or licensing fees for using Qwik in any project, commercial or otherwise.$q$, $q$The framework's ongoing development is funded primarily by Builder.io as a corporate sponsor, supplemented by community contributions on GitHub; teams adopting Qwik only incur the standard costs of hosting and deploying their own applications, not costs tied to the framework itself.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('06d2781b-fc8f-45ff-905b-0da1b9931d4e', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('23dde3d1-1c69-4fd8-bdea-41ceb5449c9a', $q$Interactive, Web-Based Proposals$q$, $q$Builds proposals, quotes and statements of work as responsive web pages instead of static PDFs, with a drag-and-drop editor.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('23dde3d1-1c69-4fd8-bdea-41ceb5449c9a', $q$Buyer Engagement Analytics$q$, $q$Tracks detailed metrics on how buyers interact with a proposal, including time spent per section and real-time view notifications.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('23dde3d1-1c69-4fd8-bdea-41ceb5449c9a', $q$QwilrPay Payment Collection$q$, $q$Lets buyers pay directly within a proposal or quote, with transaction fees that decrease at higher plan tiers.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('23dde3d1-1c69-4fd8-bdea-41ceb5449c9a', $q$E-Signature and Legal Agreements$q$, $q$Provides legally binding electronic signature capabilities so deals can be signed inside the document itself.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('23dde3d1-1c69-4fd8-bdea-41ceb5449c9a', $q$Smart Proposal Engine and AI Prefill$q$, $q$Automatically populates proposal content and pricing based on CRM data, available on the Scale plan.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('23dde3d1-1c69-4fd8-bdea-41ceb5449c9a', $q$Conditional Content Blocks$q$, $q$Shows or hides proposal sections dynamically based on buyer selections, reducing manual document customization.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('23dde3d1-1c69-4fd8-bdea-41ceb5449c9a', $q$CRM Integrations$q$, $q$Connects with HubSpot, Salesforce, Zoho and Pipedrive to sync deal data and trigger proposal creation from the pipeline.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('23dde3d1-1c69-4fd8-bdea-41ceb5449c9a', $q$Custom Branding and Identity Verification$q$, $q$Growth and Scale plans add custom branding controls and identity verification for higher-trust transactions.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('23dde3d1-1c69-4fd8-bdea-41ceb5449c9a', $q$Interactive, web-page-style proposals stand out compared to static PDF documents$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('23dde3d1-1c69-4fd8-bdea-41ceb5449c9a', $q$Detailed engagement analytics show exactly how buyers interact with a proposal$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('23dde3d1-1c69-4fd8-bdea-41ceb5449c9a', $q$Built-in payment collection and e-signature remove the need for separate tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('23dde3d1-1c69-4fd8-bdea-41ceb5449c9a', $q$Strong CRM integrations with HubSpot, Salesforce, Zoho and Pipedrive$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('23dde3d1-1c69-4fd8-bdea-41ceb5449c9a', $q$AI Prefill and the Smart Proposal Engine reduce manual document creation time on higher tiers$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('23dde3d1-1c69-4fd8-bdea-41ceb5449c9a', $q$Over 500 five-star G2 reviews and adoption by recognizable enterprise customers$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('23dde3d1-1c69-4fd8-bdea-41ceb5449c9a', $q$Per-user pricing plus document automation credits can make costs harder to predict at scale$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('23dde3d1-1c69-4fd8-bdea-41ceb5449c9a', $q$Growth and Scale plans require a minimum of 5 and 10 users respectively, which is restrictive for very small teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('23dde3d1-1c69-4fd8-bdea-41ceb5449c9a', $q$Salesforce integration and conditional content are limited to the top Scale tier$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('23dde3d1-1c69-4fd8-bdea-41ceb5449c9a', $q$QwilrPay transaction fees apply on top of the subscription cost$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('23dde3d1-1c69-4fd8-bdea-41ceb5449c9a', $q$Additional automated documents beyond the free allotment carry a per-document charge$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('23dde3d1-1c69-4fd8-bdea-41ceb5449c9a', $q$Advanced automation features have a learning curve to configure effectively$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('23dde3d1-1c69-4fd8-bdea-41ceb5449c9a', $q$What is Qwilr used for?$q$, $q$Qwilr is used to create interactive, web-based proposals, quotes and statements of work that replace static PDFs, with built-in e-signatures, payments and buyer engagement analytics.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('23dde3d1-1c69-4fd8-bdea-41ceb5449c9a', $q$How much does Qwilr cost?$q$, $q$Qwilr's Starter plan costs $35/user/month billed annually (or $49/user/month billed monthly), with Growth at $55/user/month and Scale at $75/user/month, both requiring higher user minimums and annual billing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('23dde3d1-1c69-4fd8-bdea-41ceb5449c9a', $q$Does Qwilr support e-signatures?$q$, $q$Yes, Qwilr includes legally binding electronic signature capabilities on all plans, allowing deals to be signed directly within the proposal.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('23dde3d1-1c69-4fd8-bdea-41ceb5449c9a', $q$Can buyers pay directly through a Qwilr proposal?$q$, $q$Yes, through QwilrPay, buyers can make payments directly within a proposal or quote, with transaction fees ranging from 0.25 percent on Starter to 0.05 percent on Scale.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('23dde3d1-1c69-4fd8-bdea-41ceb5449c9a', $q$When was Qwilr founded and where is it based?$q$, $q$Qwilr was founded in 2014 and is headquartered in Darlinghurst, Sydney, Australia.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('23dde3d1-1c69-4fd8-bdea-41ceb5449c9a', $q$What CRMs does Qwilr integrate with?$q$, $q$Qwilr integrates with HubSpot, Zoho and Pipedrive on all plans, with Salesforce integration available on the Scale plan.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('23dde3d1-1c69-4fd8-bdea-41ceb5449c9a', $q$What is the Smart Proposal Engine?$q$, $q$The Smart Proposal Engine is an automation feature on Qwilr's Scale plan that, along with AI Prefill, auto-populates proposal content and pricing based on CRM data.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('23dde3d1-1c69-4fd8-bdea-41ceb5449c9a', $q$How many customers does Qwilr have?$q$, $q$Qwilr reports more than 5,000 customers, including Thomson Reuters, Drata, Meltwater, Sotheby's International Realty, Yale University and OpenTable.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('23dde3d1-1c69-4fd8-bdea-41ceb5449c9a', $q$B2B Sales Proposal Creation$q$, $q$Sales teams use Qwilr to replace static PDF proposals with interactive web pages that track buyer engagement and speed up deal closure.$q$, $q$B2B sales and account executive teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('23dde3d1-1c69-4fd8-bdea-41ceb5449c9a', $q$Agency Client Proposals and Quotes$q$, $q$Agencies use Qwilr to produce branded, interactive proposals for prospective clients, with embedded pricing tables and e-signature for faster contract turnaround.$q$, $q$Marketing, creative and consulting agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('23dde3d1-1c69-4fd8-bdea-41ceb5449c9a', $q$Customer Success Renewal and Upsell Documents$q$, $q$Customer success teams use Qwilr to create interactive renewal and upsell quotes with QwilrPay for direct in-document payment collection.$q$, $q$Customer success and account management teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('23dde3d1-1c69-4fd8-bdea-41ceb5449c9a', $q$Starter$q$, $q$$35/user/month billed annually ($49/user/month billed monthly)$q$, $q$Annual or monthly, minimum 1 user$q$, NULL, $q$["E-signatures","Analytics","QwilrPay (0.25% transaction fee)","HubSpot, Zoho and Pipedrive integrations","10 free automated documents per year"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('23dde3d1-1c69-4fd8-bdea-41ceb5449c9a', $q$Growth$q$, $q$$55/user/month$q$, $q$Annual only, minimum 5 users$q$, NULL, $q$["Everything in Starter","Dedicated Customer Success Manager","Automations","Custom branding","Identity verification","150 free automated documents per year"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('23dde3d1-1c69-4fd8-bdea-41ceb5449c9a', $q$Scale$q$, $q$$75/user/month$q$, $q$Annual only, minimum 10 users$q$, NULL, $q$["Everything in Growth","Salesforce integration","Conditional content","Smart Proposal Engine","AI Prefill","600 free automated documents per year"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('23dde3d1-1c69-4fd8-bdea-41ceb5449c9a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Qwilr reimagines sales proposals, quotes and statements of work as interactive web pages rather than static PDF or Word documents, letting sales and customer-facing teams build branded, responsive documents with a drag-and-drop editor. Founded in 2014 and headquartered in Darlinghurst, Sydney, Australia, the company has grown to roughly 100 employees and more than 5,000 customers.$q$, $q$Because proposals live as web pages instead of downloadable files, Qwilr can track detailed engagement data on how buyers interact with a document, notify reps in real time when a proposal is opened, and let buyers sign and pay directly within the document itself through built-in e-signature and QwilrPay payment features.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('23dde3d1-1c69-4fd8-bdea-41ceb5449c9a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Qwilr's block-based editor lets teams assemble proposals from reusable content blocks, embedded media and interactive pricing tables, while built-in analytics reveal exactly how long buyers spent on each section and when they viewed a document. QwilrPay enables payment collection directly inside a proposal, and e-signature functionality allows deals to close without leaving the page.$q$, $q$Higher-tier plans add automation through the Smart Proposal Engine and AI Prefill, which populate proposal content and pricing from CRM data, along with conditional content blocks that adapt what a buyer sees based on their selections. Native CRM integrations with HubSpot, Salesforce, Zoho and Pipedrive keep deal data and proposal creation in sync.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('23dde3d1-1c69-4fd8-bdea-41ceb5449c9a', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Qwilr charges per user across three tiers. Starter costs $35/user/month billed annually (or $49/user/month billed monthly) with a one-user minimum and 10 free automated documents per year, with additional documents at $5 each. Growth costs $55/user/month with a five-user minimum and 150 free documents, and Scale costs $75/user/month with a ten-user minimum and 600 free documents, both billed annually only.$q$, $q$QwilrPay transaction fees also scale down with plan tier, from 0.25 percent on Starter to 0.05 percent on Scale, and pay-as-you-go document pricing drops from $5 to $2.50 per document above the Starter tier.$q$]::text[], 2);
