-- Enrichment marathon batch: QuickMail, QuickShare, Quickwit, QuillBot, QuotaPath, Quso.ai, Qwik, Qwilr

-- ── QuickMail ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Cold email and LinkedIn outreach automation platform that helps sales teams and lead generation agencies book more meetings through multi-channel campaigns with unlimited senders and no per-seat pricing.$q$, short_description),
  pricing_model = COALESCE($q$Flat-rate subscription with unlimited senders and users per workspace, billed monthly with a 14-day free trial$q$, pricing_model),
  starting_price = COALESCE($q$$49/month (Starter plan)$q$, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE($q$1-10 employees$q$, company_size),
  headquarters = COALESCE($q$Zurich, Switzerland$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$QuickMail Pricing and Features 2026: Cold Email and LinkedIn Outreach Tool$q$, seo_title),
  seo_meta_description = COALESCE($q$QuickMail is a cold email and LinkedIn outreach platform with unlimited senders, inbox rotation and AI writing tools. Compare plans starting at $49/month.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$QuickMail is a cold outreach automation platform built for sales teams, growth marketers and lead generation agencies that need to run email and LinkedIn campaigns at scale. Founded in 2014 by Jeremy Chatelaine and headquartered in Zurich, Switzerland, QuickMail (found at quickmail.com, formerly quickmail.io) positions itself as a consolidated alternative to stitching together separate tools for email sending, deliverability monitoring, domain warm-up and LinkedIn prospecting. The platform's core differentiator is unlimited email senders, unlimited LinkedIn accounts and unlimited users on every paid plan, so pricing does not scale per seat the way most competing cold email tools do. Instead, plans are priced by monthly email volume and uploaded contact list size. As of 2026, QuickMail offers three tiers: Starter at $49/month (5,000 emails per month, 1,000 uploaded contacts, one workspace), Growth at $99/month (100,000 emails per month, 25,000 contacts), and Agency at $299/month (500,000 emails per month, 100,000 contacts, two workspaces with additional workspaces available for $49 each). All plans include a 14-day free trial and no long-term contract is required. Core functionality centers on QuickMail's Inbox Rotation feature, which automatically distributes outbound sends across multiple connected mailboxes to protect sender reputation and avoid spam filters, paired with a free automated email warm-up tool called MailFlow. The platform also includes a browser extension for LinkedIn outreach that lets users build prospect lists using LinkedIn's ICP filtering and run connection-request and messaging sequences alongside email sequences, with replies from both channels consolidated into a single unified inbox. AI-assisted features include a reword-with-AI tool for varying email copy across a campaign to reduce spam-pattern detection, along with automated deliverability insights that flag issues like poor sending reputation or blacklist placement. QuickMail also offers infrastructure services such as domain purchasing and mailbox configuration to help agencies and larger teams spin up cold email infrastructure quickly. Native integrations include HubSpot and Pipedrive CRMs, plus a Zapier connector and, on Growth and Agency plans, API and webhook access for custom workflows. QuickMail has been recognized as a G2 High Performer and has won a G2 Best Estimated ROI award, with user reviews consistently citing ease of use, responsive support and effective deliverability management as strengths, while some reviews note a learning curve around multi-step sequence setup and reporting that is less granular than enterprise sales engagement suites. QuickMail primarily competes with tools like Instantly, Smartlead, Lemlist and Woodpecker in the cold email and sales engagement category, and is best suited for small-to-midsize sales teams, agencies running outreach on behalf of clients, and B2B founders who want to manage high email volume without paying escalating per-user fees.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'bf18ee80-5dd1-4c12-9e38-a3430262d485';

