-- ── QuickShare ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Open-source, self-hosted file sharing application for transferring, organizing and managing files across your own devices without relying on third-party cloud storage.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source; self-hosted with no subscription or paid tiers$q$, pricing_model),
  starting_price = COALESCE($q$Free (open source, self-hosted)$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE($q$Not publicly disclosed (open-source project maintained primarily by developer ihexxa, with community contributors)$q$, company_size),
  headquarters = COALESCE($q$Not publicly disclosed (open-source project with no registered corporate headquarters)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Quickshare Review 2026: Free Self-Hosted File Sharing Software$q$, seo_title),
  seo_meta_description = COALESCE($q$Quickshare is a free, open-source, self-hosted file sharing app built with Go, React and TypeScript. See features, deployment options and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Quickshare is a free, open-source, self-hosted file sharing application built by developer ihexxa (George) and hosted on GitHub at github.com/ihexxa/quickshare, with a project site at ihexxa.github.io/quickshare.site. Unlike commercial cloud storage products, Quickshare is software that users download and run on their own hardware, whether a home server, a small NAS, a cloud VPS or a personal computer, giving them full control over where their files live. The project is built with Go on the backend and React with TypeScript on the frontend, and it is released under the LGPL-3.0 open-source license, meaning there is no company, subscription, or paid tier behind it; it is entirely free to use, and revenue or company financial details do not apply since it is a community software project rather than a commercial entity. As of the latest release cycle, the GitHub repository has accumulated roughly 632 stars and 40 forks, with 58 total tagged releases, the most recent being version 0.11.4, indicating ongoing active maintenance. Core functionality covers everyday file management tasks: uploading, downloading, creating, deleting, and moving files and folders; resumable uploads and downloads so large transfers can survive network interruptions; in-browser file and folder management; and fuzzy search across files and folders using multiple keywords. Sharing is a central feature, letting users share individual files or entire directories with others, including anonymous, link-based sharing that does not require the recipient to have an account, plus QR code generation so a shared folder can be opened instantly on a mobile device. For teams or households sharing one instance, Quickshare supports multiple user accounts with role-based permissions distinguishing regular users from administrators, along with per-user upload and download speed limits and per-user storage quotas, which helps prevent any single user from consuming all available bandwidth or disk space on a shared server. The application is cross-platform, running on Linux, macOS and Windows, and it can be deployed either by downloading a pre-built binary from the GitHub releases page or by running it in a container via Docker, which is the most common deployment path referenced in community guides and self-hosting directories like Awesome Docker Compose and LibreSelfHosted. Quickshare also supports streaming uploads, which makes it usable behind content delivery networks or reverse proxies without buffering entire files in memory first, an adaptive UI that adjusts to different screen sizes, internationalization (i18n) support for multiple display languages, and cosmetic customization options like wallpaper backgrounds. Because it has no company behind it, there is no funding history, headquarters, or founding date in the traditional business sense; the "About" identity of the project is its GitHub maintainer and its open-source community. Quickshare is best understood as a lightweight alternative to larger self-hosted file-sharing platforms like Nextcloud or Seafile for users who want a simpler, single-binary tool focused specifically on fast file transfer and sharing between personal devices, rather than a full groupware or office-suite replacement.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '84a38488-775c-4325-9b1d-4639474c2773';

