-- ── Quickwit ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Open-source, cloud-native search and analytics engine for logs and distributed traces, built in Rust for sub-second search directly on object storage; acquired by Datadog in 2025.$q$, short_description),
  pricing_model = COALESCE($q$Open source under Apache License 2.0 for self-managed deployment; enterprise and managed support now offered through Datadog following its acquisition of Quickwit$q$, pricing_model),
  starting_price = COALESCE($q$Free (open source, self-hosted); Datadog-managed offering priced separately by Datadog$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE($q$Approximately 3-10 employees prior to its 2025 acquisition by Datadog, now integrated into Datadog's engineering organization$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, USA (founding team originally distributed across Paris, Tokyo and New York)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Quickwit Review 2026: Open-Source Log Search Engine, Now Part of Datadog$q$, seo_title),
  seo_meta_description = COALESCE($q$Quickwit is an open-source, Rust-built search engine for logs and traces that runs directly on object storage. Learn about its features and Datadog acquisition.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Quickwit is an open-source search and analytics engine purpose-built for querying very large volumes of log and trace data with sub-second latency, using cloud object storage such as Amazon S3, MinIO or Ceph as its primary data layer instead of requiring data to be pre-loaded onto local disks. The company was founded in 2020 by a team of engineers with deep search-technology backgrounds, and was headquartered with a distributed team across San Francisco, Paris, Tokyo and New York. Quickwit raised a $2.6 million seed round in March 2022 led by firstminute Capital and FirstMark. On January 9, 2025, Datadog announced its acquisition of Quickwit, describing the deal as a way to strengthen its log management and observability offerings, particularly for customers in regulated industries such as financial services, insurance and healthcare that need to keep log data resident in specific environments or regions for compliance reasons. As part of the acquisition, Quickwit committed to releasing a major update of its search engine under the more permissive Apache License 2.0 to reassure its open-source community that the technology would remain available outside of Datadog's commercial products. Technically, Quickwit is written in Rust and built on top of the Tantivy full-text search library, using vectorized query processing and SIMD instructions for performance. Its architecture decouples compute from storage, so search nodes can be scaled independently of where the underlying data sits, and indexes can be queried directly from object storage without a separate ingestion step into a proprietary database format. The engine is schemaless, supports horizontal scaling and multi-tenancy through data partitioning, and offers native ingestion support for OpenTelemetry and Jaeger tracing formats, making it well suited for observability pipelines that need to store and search high-cardinality trace and log data cost-effectively. It also supports GDPR-compliant data deletion, REST API access, and both single-node and multi-node deployment models for on-premise or cloud environments. Prior to the acquisition, Quickwit positioned itself as a lower-cost, cloud-native alternative to systems like Elasticsearch for log search use cases, emphasizing that because it searches data in place on object storage rather than requiring expensive replicated local storage, operating costs could be significantly lower for very large log volumes. Customers referenced in its go-to-market materials and acquisition coverage include organizations with large-scale logging needs such as Binance and Mezmo. Since the Datadog acquisition, Quickwit's commercial future is tied to Datadog's product roadmap, with Datadog absorbing the underlying technology into its observability and log management suite, while continuing to support the open-source Quickwit engine itself for self-managed and community use. Organizations evaluating Quickwit today are effectively choosing between running the open-source engine themselves for full control and lower infrastructure cost, or engaging Datadog for a managed, supported version integrated with Datadog's broader observability platform.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '1ad07660-a8fd-4c45-a63d-f9199fe54fa9';

