-- ── QuillBot ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$AI-powered writing assistant for paraphrasing, grammar checking, plagiarism detection and translation, used by students and professionals to improve and rewrite text.$q$, short_description),
  pricing_model = COALESCE($q$Freemium subscription with a limited free tier and paid Premium and Team plans$q$, pricing_model),
  starting_price = COALESCE($q$Free plan available; Premium from $8.33/month billed annually ($99.95/year)$q$, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE($q$51-200 employees (part of Learneo, Inc.)$q$, company_size),
  headquarters = COALESCE($q$Chicago, Illinois, USA$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Supports translation and grammar tools across 50-plus languages including Spanish, French, German, Portuguese, Arabic, Hindi, Japanese, Korean and Chinese$q$]::text[],
  seo_title = COALESCE($q$QuillBot Review 2026: Pricing, Features and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$QuillBot is an AI paraphrasing and grammar tool with a free plan and Premium from $8.33/month. See features, pricing plans, pros, cons and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$QuillBot is an AI-powered writing assistant best known for its paraphrasing tool, which rewrites sentences and paragraphs in different tones and styles while preserving meaning. The company was formed in 2017 and is headquartered in Chicago, Illinois. In September 2021, QuillBot was acquired by Learneo (the parent company formerly known as Course Hero, Inc.), which rebranded publicly as Learneo in 2023 under co-founder Andrew Grauer; QuillBot continues to operate as one of Learneo's flagship products, led by CEO Rohan Gupta, one of its original co-founders alongside David Silin and Anil Jason. QuillBot's core paraphrasing engine offers multiple rewriting modes, such as Standard, Fluency, Formal, Academic, Simple, Creative, Expand and Shorten, letting users adjust output for different audiences and contexts. Around the paraphraser, QuillBot has built a broader suite of writing tools including a grammar and punctuation checker, a plagiarism checker that scans against billions of web pages and academic sources, an AI text summarizer, a citation generator supporting styles like APA, MLA and Chicago, and QuillBot Translate, an AI translation tool supporting more than 50 languages. Pricing follows a freemium model: the Free plan allows a 125-word limit per paraphrase along with basic grammar checking, while QuillBot Premium unlocks unlimited-length paraphrasing, advanced grammar and word-choice suggestions, the plagiarism checker, translation tools and priority support. Premium is priced at $19.95 per month when billed monthly, $39.95 per quarter (about $13.31 per month), or $99.95 per year (about $8.33 per month), representing roughly a 58 percent discount versus paying monthly. QuillBot also offers a Team plan for businesses and schools starting around $7.50 per user per month for groups of 2 to 10 seats billed annually, and offers discounted Premium access to verified students at about $6.25 per month. QuillBot integrates into common writing environments through a Chrome browser extension, a Microsoft Word add-in, and both iOS and Android mobile apps, letting users access paraphrasing and grammar checking without leaving the document or webpage they are working in. The company reports widespread adoption among students, non-native English speakers, content writers, marketers and academic researchers, and has processed billions of paraphrased sentences since launch, according to its own marketing materials. On review platforms such as G2 and Capterra, QuillBot is generally well rated for ease of use and the quality of its paraphrasing suggestions, with common critiques centered on the free plan's restrictive word limits, occasional awkward phrasing in heavily paraphrased academic text, and growing competition from general-purpose AI chat tools like ChatGPT that can perform similar rewriting tasks as part of a broader feature set. QuillBot differentiates itself by focusing specifically on writing refinement workflows, purpose-built UI for paraphrasing and grammar, and academic-oriented features like plagiarism checking and citation generation that general AI chatbots do not offer out of the box.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f18cd757-37d4-43bb-966d-11c389f63bb7';

