  short_description = COALESCE($q$AI platform that automatically repurposes long-form videos, podcasts and livestreams into short, captioned social media clips optimized for TikTok, Instagram Reels, YouTube Shorts and LinkedIn.$q$, short_description),
  pricing_model = COALESCE($q$Freemium subscription with credit-based usage limits per plan$q$, pricing_model),
  starting_price = COALESCE($q$Free plan available; paid plans from $19/month billed annually (Lite plan)$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE($q$Approximately 25-34 employees$q$, company_size),
  headquarters = COALESCE($q$New York, New York, USA$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Captions and transcription supported in 100-plus languages$q$]::text[],
  seo_title = COALESCE($q$Quso.ai Review 2026: Pricing, Features and AI Video Clipping Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Quso.ai (formerly Vidyo.ai) turns long videos into short social clips with AI. See pricing from $19/month, key features, pros, cons and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Quso.ai, formerly known as Vidyo.ai, is an AI-powered content repurposing platform that converts long-form videos, podcasts and livestreams into short, vertical, captioned clips designed for platforms like TikTok, Instagram Reels, YouTube Shorts and LinkedIn. The company was co-founded in December 2021 by Vedant Maheshwari and Kushagra Pandya and is headquartered in New York City. According to a Latka case study, Quso.ai reached roughly $3.7 million in annual revenue with a team of about 34 people in 2025, and the company states it has been used by more than four million creators, podcasters and brands worldwide since launch. The core product analyzes an uploaded long-form video or podcast recording and uses AI to identify the most engaging moments, scoring segments by their estimated virality potential so creators do not have to manually scrub through hours of footage to find clip-worthy content. Once moments are identified, the platform automatically generates short clips with word-level animated captions in more than 100 languages, removes filler words and silences, and reformats output into multiple aspect ratios (16:9, 9:16 and 1:1) to fit different platforms from a single source upload. Beyond clipping, Quso.ai includes a text-based AI video editor with a built-in B-roll library, a Brand Kit for maintaining consistent fonts, colors and logos across all generated clips, and a social media scheduler and Content Planner that lets users plan and auto-publish clips to multiple platforms from a single calendar view. Quso.ai also provides a "Viddy" AI assistant on its top-tier plan and social media analytics with AI-generated performance insights to help creators understand which clips are resonating. Pricing follows a freemium, credit-based model, where each credit corresponds to roughly one minute of processed video. The Free plan includes 75 monthly credits with 720p exports, a watermark, and TikTok publishing. Paid tiers include Lite at $19/month billed annually (or $29/month billed monthly) for unlimited 1080p exports, an advanced desktop editor, publishing to six platforms and 10GB of storage; Essential at $26/month billed annually (or $39/month monthly), marketed as the most popular plan, adding AI filler and silence removal, external content support, the Content Planner and 25GB of storage; and Growth at $33/month billed annually (or $49/month monthly), adding a custom Brand Kit, the Viddy AI assistant, unlimited scheduling and analytics, custom branding, priority support and 75GB of storage. Annual billing is roughly 33 percent cheaper per month than monthly billing and doubles the included monthly credits. Quso.ai positions itself as a consolidated alternative to using separate tools such as Opus Clip, Descript, CapCut, Hootsuite, Buffer and Vizard together, targeting content creators, podcasters, business and mindset coaches, video marketers and content agencies that need to turn one long recording into a week's worth of platform-native short-form content.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '79b50fbc-218a-44ae-a060-2d87cb1dda56';

