-- ── Qwilr ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Interactive proposal and quote software that turns sales documents into responsive web pages with embedded pricing, e-signatures, payments and buyer engagement analytics.$q$, short_description),
  pricing_model = COALESCE($q$Per-user subscription, billed annually or monthly, with document automation credits and QwilrPay transaction fees on top$q$, pricing_model),
  starting_price = COALESCE($q$$35/user/month billed annually ($49/user/month billed monthly) for the Starter plan$q$, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE($q$Approximately 100 employees$q$, company_size),
  headquarters = COALESCE($q$Darlinghurst, Sydney, Australia$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Qwilr Review 2026: Pricing, Features and Interactive Proposal Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Qwilr turns proposals and quotes into interactive web pages with e-signatures and payments. See pricing from $35/user/month, features, pros and cons.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Qwilr is a proposal and quote management platform that replaces traditional static PDF and Word-based sales documents with interactive, responsive web pages. Founded in 2014 and headquartered in Darlinghurst, Sydney, Australia, Qwilr was built by co-founders including Mark Tanner and Dylan Baskind, and has grown into a company with roughly 100 employees distributed across multiple continents. According to a Latka case study, Qwilr generated about $17.7 million in annual revenue and served roughly 1,000 customers as of 2024. The company reports more than 5,000 customers overall, including notable names such as Thomson Reuters, Drata, Meltwater, Sotheby's International Realty, Yale University and OpenTable, and highlights more than 500 five-star reviews on G2. Qwilr's core product lets sales, marketing and customer success teams build proposals, quotes, statements of work and other client-facing documents using a drag-and-drop, block-based editor, producing output that renders as a branded, mobile-responsive web page rather than a downloadable file. Because documents are hosted as web pages, Qwilr can track detailed buyer engagement analytics, such as how long a recipient spent on each section and when they viewed the document, and can send real-time notifications to the sales rep when a prospect opens or interacts with a proposal. The platform includes QwilrPay, a built-in payment collection feature that lets buyers pay directly from within a proposal or quote, along with legally binding e-signature capabilities so deals can be signed without leaving the document. Higher tiers add automation features such as a Smart Proposal Engine and AI Prefill, which auto-populate proposal content and pricing based on CRM data, along with conditional content blocks that show or hide sections based on buyer selections, reducing the manual work of customizing every document from scratch. Qwilr integrates with CRM platforms including HubSpot, Salesforce, Zoho and Pipedrive to sync deal data and automatically trigger proposal creation from pipeline stages. Pricing is structured in three tiers, all charged per user: Starter costs $35 per user per month billed annually (or $49 per user per month billed monthly) with a minimum of one user, and includes e-signatures, analytics, QwilrPay, core CRM integrations and 10 free automated documents per year, with additional documents billed at $5 each; Growth costs $55 per user per month with a five-user minimum, billed annually only, adding a dedicated Customer Success Manager, deeper automation, custom branding, identity verification and 150 free automated documents; and Scale costs $75 per user per month with a ten-user minimum, also annual-only, adding Salesforce integration, conditional content, the Smart Proposal Engine, AI Prefill, premium design services and 600 free automated documents, with pay-as-you-go documents dropping to $2.50 each on Growth and Scale. QwilrPay transaction fees also decrease as plan tier increases, from 0.25 percent on Starter down to 0.05 percent on Scale. Qwilr reports internal benchmarks claiming customers see a 20 percent or greater increase in win rates, a roughly five-month payback period on their investment, a 20 percent reduction in deal closure time, and a 75 percent reduction in time spent creating sales materials, though these figures come from the company's own marketing and should be treated as vendor-reported claims rather than independently audited statistics. Qwilr competes most directly with proposal and document automation tools like PandaDoc, Proposify and Better Proposals, and it is best suited for B2B sales, agency and customer success teams that want proposals to double as an engagement and analytics channel rather than a one-way static document.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '23dde3d1-1c69-4fd8-bdea-41ceb5449c9a';

